root.js-content:
stp.writeLog("Begin: 006 R2 InTSU JS");
var GetTxId1 = stp.getValue("/Document/AmdmntRjctnNtfctn/TxId","Id");
var GetTxId=GetTxId1[0];

//get C_MAIN_REF
stp.writeLog("GetTxId="+GetTxId);
var bu=stp.getTSUUnitCode();
var fld_list = stp.addFieldList(null,"C_MAIN_REF");    
var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId);
sql_condition     = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu); 
sql_condition = stp.addSQLCondition(sql_condition,"C_TRX_STATUS","M");
var result = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
var mainRef = stp.getDBFieldValue(result,"C_MAIN_REF");
stp.writeLog("mainRef="+mainRef);
stp.updateFieldValue("","C_MAIN_REF",mainRef);
stp.updateFieldValue("","C_UNIT_CODE",bu);

//Get TSU_AMD_ref
var fld_list            = stp.addFieldList(null,"TSU_AMD_REF");    
var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId);
sql_condition    = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu); 
sql_condition = stp.addSQLCondition(sql_condition,"C_TRX_STATUS","M");
var result             = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
var amdNo_org   = stp.getDBFieldValue(result,"TSU_AMD_REF");
stp.updateFieldValue("/root/domData","TSU_AMD_REF",amdNo_org);
stp.updateFieldValue("","C_TRX_REF",amdNo_org);
stp.writeLog("amdNo_org="+amdNo_org);

var REJT= stp.getValue("/Document/AmdmntRjctnNtfctn/RjctdAmdmntNb","Nb");
if (REJT != null)
{ 
var sts="";
stp.updateFieldValue("TSU_RESP_RESULT",sts);
}

var OurBIC=stp.getTSUBIC();

var FirstREF1= stp.getValue("/Document/AmdmntRjctnNtfctn/UsrTxRef","Id");
var FirstREF = FirstREF1[0];
var FirstBIC1 = stp.getValue("/Document/AmdmntRjctnNtfctn/UsrTxRef/IdIssr","BIC");
var FirstBIC = FirstBIC1[0];
var SecondREF1 =stp.getValue("/Document/AmdmntRjctnNtfctn/UsrTxRef","Id");
var SecondREF = SecondREF1[1];
var SecondBIC1 =stp.getValue("/Document/AmdmntRjctnNtfctn/UsrTxRef/IdIssr","BIC");
var SecondBIC = SecondBIC1[1];
stp.writeLog("SecondBIC"+SecondBIC);

if (FirstBIC == "undefined" || FirstBIC == "null" || FirstBIC==null)
{
    FirstBIC = '';
    FirstREF = '';
}

if (SecondBIC == "undefined" || SecondBIC == "null" || SecondBIC==null)
{   
    SecondBIC = '';
    SecondREF = '';
}

var BIC1 = stp.compareString(FirstBIC,OurBIC);
var BIC2= stp.compareString(SecondBIC,OurBIC);
stp.writeLog("BIC1--------------------" +BIC1);
stp.writeLog("BIC2--------------------" +BIC2);

if(BIC1 == "true")
{   stp.writeLog(" -----------------------------------------------------");
	stp.updateFieldValue("/root/domData","TSU_OUR_BIC",FirstBIC);
	stp.updateFieldValue("/root/domData","TSU_OUR_REF",FirstREF);
	stp.updateFieldValue("/root/domData","TSU_THEIR_REF",SecondREF);
	stp.updateFieldValue("/root/domData","TSU_THEIR_BIC",SecondBIC);	
}
if(BIC2 == "true")
{   stp.writeLog("-----------------------------------------------------");
	stp.updateFieldValue("/root/domData","TSU_OUR_BIC",SecondBIC);
	stp.updateFieldValue("/root/domData","TSU_OUR_REF",SecondREF);
	stp.updateFieldValue("/root/domData","TSU_THEIR_REF",FirstREF);
	stp.updateFieldValue("/root/domData","TSU_THEIR_BIC",FirstBIC);	
}

    stp.writeLog("End:008 R2 InTSU JS");

	stp.setAutoProcess(true);   

    stp.writeLog("Begin assign 008 R2 function ");

	stp.setFunc("R2AmendmentsRejectionNoti");

	stp.writeLog("End assign 008 R2 function ");
